-- ==========================================
-- SABICREST SUPABASE DATABASE SETUP SCRIPT
-- ==========================================

-- 1. Create table schemas for the platform modules if they don't exist

CREATE TABLE IF NOT EXISTS public.admin_activities (
  id TEXT PRIMARY KEY,
  timestamp TEXT NOT NULL,
  admin_id TEXT NOT NULL,
  admin_name TEXT NOT NULL,
  admin_email TEXT NOT NULL,
  action TEXT NOT NULL,
  details TEXT NOT NULL,
  ip_address TEXT
);

CREATE TABLE IF NOT EXISTS public.trainer_applications (
  id TEXT PRIMARY KEY,
  trainer_id TEXT NOT NULL,
  trainer_name TEXT NOT NULL,
  trainer_email TEXT NOT NULL,
  course_id TEXT NOT NULL,
  course_title TEXT NOT NULL,
  course_category TEXT NOT NULL,
  experience_years INTEGER NOT NULL,
  portfolio_url TEXT,
  workshop_address TEXT,
  equipments_owned TEXT,
  credentials_link TEXT,
  status TEXT NOT NULL,
  rejection_reason TEXT,
  submitted_at TEXT NOT NULL
);

CREATE TABLE IF NOT EXISTS public.users (
  id TEXT PRIMARY KEY,
  name TEXT NOT NULL,
  email TEXT UNIQUE NOT NULL,
  role TEXT NOT NULL DEFAULT 'student',
  password TEXT,
  avatar TEXT,
  verified BOOLEAN NOT NULL DEFAULT FALSE,
  joined_date TEXT NOT NULL,
  status TEXT NOT NULL DEFAULT 'active',
  bio TEXT,
  skills TEXT[],
  team_id TEXT,
  phone TEXT,
  slack_handle TEXT,
  location TEXT,
  enrolled_course_ids TEXT[],
  trainer_business_name TEXT,
  use_business_name BOOLEAN NOT NULL DEFAULT FALSE,
  trainer_signature TEXT,
  trainer_role TEXT,
  streak_count INTEGER DEFAULT 0,
  streak_expiry TEXT,
  streak_freezes INTEGER DEFAULT 2,
  streak_freeze_active BOOLEAN DEFAULT FALSE,
  last_streak_activity_date TEXT,
  streak_logs JSONB
);

CREATE TABLE IF NOT EXISTS public.messages (
  id TEXT PRIMARY KEY,
  sender_id TEXT NOT NULL,
  sender_name TEXT NOT NULL,
  sender_avatar TEXT,
  receiver_id TEXT,
  channel_id TEXT,
  content TEXT NOT NULL,
  encrypted_content TEXT NOT NULL,
  timestamp TEXT NOT NULL,
  is_encrypted BOOLEAN NOT NULL DEFAULT TRUE,
  algorithm TEXT NOT NULL,
  reply_to_id TEXT,
  reply_to_sender TEXT,
  reply_to_text TEXT,
  reactions JSONB,
  attachment_url TEXT,
  attachment_name TEXT,
  attachment_type TEXT,
  delivered BOOLEAN DEFAULT FALSE,
  read BOOLEAN DEFAULT FALSE
);

CREATE TABLE IF NOT EXISTS public.hub_messages (
  id TEXT PRIMARY KEY,
  sender_id TEXT NOT NULL,
  sender_name TEXT NOT NULL,
  sender_avatar TEXT,
  content TEXT NOT NULL,
  timestamp TEXT NOT NULL,
  tag TEXT NOT NULL,
  is_solved BOOLEAN DEFAULT FALSE,
  reply_to_id TEXT,
  reply_to_sender TEXT,
  reply_to_text TEXT,
  reactions JSONB,
  attachment_url TEXT,
  attachment_name TEXT,
  attachment_type TEXT
);

CREATE TABLE IF NOT EXISTS public.events (
  id TEXT PRIMARY KEY,
  title TEXT NOT NULL,
  description TEXT NOT NULL,
  date TEXT NOT NULL,
  time TEXT NOT NULL,
  duration_minutes INTEGER NOT NULL,
  host_id TEXT NOT NULL,
  host_name TEXT NOT NULL,
  attendee_id TEXT NOT NULL,
  status TEXT NOT NULL,
  meet_link TEXT,
  role_type TEXT NOT NULL
);

CREATE TABLE IF NOT EXISTS public.assignments (
  id TEXT PRIMARY KEY,
  title TEXT NOT NULL,
  description TEXT NOT NULL,
  due_date TEXT NOT NULL,
  max_points INTEGER NOT NULL,
  student_id TEXT NOT NULL,
  student_name TEXT NOT NULL,
  trainer_id TEXT NOT NULL,
  trainer_name TEXT NOT NULL,
  submitted_at TEXT,
  submission_content TEXT,
  link_url TEXT,
  status TEXT NOT NULL,
  grade TEXT,
  points INTEGER,
  feedback TEXT,
  graded_at TEXT,
  course_id TEXT
);

CREATE TABLE IF NOT EXISTS public.teams (
  id TEXT PRIMARY KEY,
  name TEXT NOT NULL,
  project_title TEXT NOT NULL,
  description TEXT,
  members TEXT[],
  tasks JSONB,
  shared_notes TEXT
);

CREATE TABLE IF NOT EXISTS public.certificates (
  id TEXT PRIMARY KEY,
  student_id TEXT NOT NULL,
  student_name TEXT NOT NULL,
  curriculum_title TEXT NOT NULL,
  trainer_name TEXT NOT NULL,
  issued_date TEXT NOT NULL,
  hash TEXT NOT NULL,
  status TEXT NOT NULL,
  trainer_business_name TEXT,
  use_business_name BOOLEAN NOT NULL DEFAULT FALSE,
  trainer_signature TEXT,
  trainer_role TEXT
);

CREATE TABLE IF NOT EXISTS public.notifications (
  id TEXT PRIMARY KEY,
  user_id TEXT NOT NULL,
  title TEXT NOT NULL,
  message TEXT NOT NULL,
  type TEXT NOT NULL,
  read BOOLEAN NOT NULL DEFAULT FALSE,
  created_at TEXT NOT NULL
);

CREATE TABLE IF NOT EXISTS public.enrollments (
  id TEXT PRIMARY KEY,
  student_id TEXT NOT NULL,
  student_name TEXT NOT NULL,
  student_email TEXT NOT NULL,
  course_id TEXT NOT NULL,
  course_title TEXT NOT NULL,
  trainer_id TEXT NOT NULL,
  trainer_name TEXT NOT NULL,
  amount NUMERIC NOT NULL,
  payment_link_url TEXT NOT NULL,
  payment_status TEXT NOT NULL,
  payment_reference TEXT,
  submitted_at TEXT,
  verified_at TEXT,
  rejection_reason TEXT,
  completed BOOLEAN DEFAULT FALSE,
  completed_at TEXT
);

-- Ensure table column 'admin_email' exists on admin_activities if table already existed
ALTER TABLE IF EXISTS public.admin_activities ADD COLUMN IF NOT EXISTS admin_email TEXT;


-- 2. Create the courses and curricula tables which power the register courses catalog

CREATE TABLE IF NOT EXISTS public.courses (
  id TEXT PRIMARY KEY,
  trainer_id TEXT NOT NULL,
  trainer_name TEXT NOT NULL,
  title TEXT NOT NULL,
  description TEXT NOT NULL,
  category TEXT NOT NULL,
  level TEXT NOT NULL,
  duration_weeks INTEGER NOT NULL,
  modules JSONB NOT NULL DEFAULT '[]'::jsonb,
  status TEXT NOT NULL,
  rejection_reason TEXT,
  submitted_at TEXT NOT NULL,
  approved_at TEXT,
  price NUMERIC,
  pricing_beginner NUMERIC,
  pricing_intermediate NUMERIC,
  pricing_expert NUMERIC,
  equipment TEXT,
  outcomes TEXT,
  image_url TEXT,
  cohort_start_date TEXT,
  early_draw_processed BOOLEAN DEFAULT FALSE,
  full_draw_processed BOOLEAN DEFAULT FALSE
);

CREATE TABLE IF NOT EXISTS public.curricula (
  id TEXT PRIMARY KEY,
  trainer_id TEXT NOT NULL,
  trainer_name TEXT NOT NULL,
  title TEXT NOT NULL,
  description TEXT NOT NULL,
  category TEXT NOT NULL,
  level TEXT NOT NULL,
  duration_weeks INTEGER NOT NULL,
  modules JSONB NOT NULL DEFAULT '[]'::jsonb,
  status TEXT NOT NULL,
  rejection_reason TEXT,
  submitted_at TEXT NOT NULL,
  approved_at TEXT,
  price NUMERIC,
  pricing_beginner NUMERIC,
  pricing_intermediate NUMERIC,
  pricing_expert NUMERIC,
  equipment TEXT,
  outcomes TEXT,
  image_url TEXT,
  cohort_start_date TEXT,
  early_draw_processed BOOLEAN DEFAULT FALSE,
  full_draw_processed BOOLEAN DEFAULT FALSE
);

-- TRUNCATE existing records in courses and curricula to prevent primary key collisions on pre-seeds
TRUNCATE TABLE public.courses CASCADE;
TRUNCATE TABLE public.curricula CASCADE;

